mapper.select:
SELECT w.wanted_id, w.user_id, w.book_title, w.author, w.isbn, w.cover_image, w.description, w.max_price, w.status, w.view_count, w.create_time, w.update_time, w.deleted, u.username as username FROM book_wanted w LEFT JOIN user u ON w.user_id = u.user_id WHERE w.deleted = 0
AND w.book_title LIKE CONCAT('%', #{bookTitle}, '%')
AND w.user_id = #{userId}
AND w.status = #{status}
ORDER BY w.create_time DESC
